class Solution:
    def minOperations(self, nums, x):
        total = sum(nums)
        target = total - x
        if target < 0:
            return -1
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        best = -1
        for i in range(n + 1):
            for j in range(i, n + 1):
                if prefix[j] - prefix[i] == target:
                    length = j - i
                    if length > best:
                        best = length
        return n - best if best != -1 else -1

